import React from "react";
import html2canvas from 'html2canvas';
import TheTitle from './components/theTitle';
import TheSubTitle from './components/theSubTitle';
import TheAText from './components/theAText';

class christmas extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            snow:require("./img/8.png").default,
            audio: require("./audio/jingleBells.mp3").default,
            fontText : '圣诞快乐',
            fontsize : null,
            color : 'rgb(191, 10, 16)',
            fontWeight : 200,
            lineHeight: 1.5,
            letterSpacing : 1,
            subfontText : 'Merry Christmas',
            subfontsize : null,
            subcolor : 'rgb(51, 51, 51)',
            subfontWeight : 600,
            sublineHeight: 1.3,
            subletterSpacing : 1,
            afontText : '虽然，只是一句轻轻的问候，<br/>却包含着浓浓的真情，<br/>却承载着深深的厚意，<br/>不管我们近在咫尺，还是远在天涯，<br/>愿好运永远伴随你，<br/>愿你一生都平安幸福。',
            afontsize : null,
            acolor : 'rgb(255, 204, 51)',
            afontWeight : 400,
            alineHeight: 2,
            aletterSpacing : 0,
        };
    };
    getDatas(data,data1,data2,data3,data4,data5){
        //把子组件传递过来的值赋给this.state中的属性
        this.setState({
            fontText:data,
            fontsize: data1,
            color:data2,
            fontWeight:data3,
            lineHeight:data4,
            letterSpacing:data5
        });
    }
    subgetDatas(data,data1,data2,data3,data4,data5){
        //把子组件传递过来的值赋给this.state中的属性
        this.setState({
            subfontText:data,
            subfontsize: data1,
            subcolor:data2,
            subfontWeight:data3,
            sublineHeight:data4,
            subletterSpacing:data5
        });
    }
    agetDatas(data,data1,data2,data3,data4,data5){
        //把子组件传递过来的值赋给this.state中的属性
        this.setState({
            afontText:data,
            afontsize: data1,
            acolor:data2,
            afontWeight:data3,
            alineHeight:data4,
            aletterSpacing:data5
        });
    }
    componentDidMount() {
        const clickEvent = (function() {
            if ('ontouchstart' in document.documentElement === true){
                return 'touchstart';
            }else{
                return 'mousedown';
            }
        })();
        let that = this;
        let snow = this.state.snow;
        let audioSrc = this.state.audio;
        (function(){
            let cardReverseBgbox = document.querySelector('.cardReverseBgbox');
            let cardReverseBg = document.querySelectorAll('.cardReverseBg');
            for(let j = 0;j<cardReverseBg.length;j++){
                for(let i = 0;i< 75;i++){
                    let span = document.createElement('span');
                    let img = document.createElement('img');
                    img.src = snow;
                    span.appendChild(img);
                    cardReverseBg[j].appendChild(span)
                }
            }
            let snowItems = document.querySelectorAll('.cardReverseBg span');
            for(let i = 0;i<snowItems.length;i++){
                snowItems[i].style.width = Math.random() * 5 + '%';
                snowItems[i].style.left = Math.random() * 100 + '%';
                snowItems[i].style.top = Math.random() * 100 + '%';
                snowItems[i].style.opacity = Math.random() * 1 + 0.4;
                snowItems[i].style.transform = 'translate3d('+ Math.random() * 100  + '%,0,0)';
            }
            let newCardReverseBg = cardReverseBg[0].cloneNode(true);
            cardReverseBgbox.appendChild(newCardReverseBg);
        })();

        (function cardReversebody() {
            document.querySelector('.cardReversebody').classList.add('active');
        })();

        function initMusic() {
            //动态创建一个audio节点
            var audio = document.createElement('audio');
            audio.setAttribute('id', 'audio');
            audio.setAttribute('autoplay', 'autoplay');
            audio.setAttribute('loop', 'loop');
            audio.innerHTML = `<source src="` + audioSrc + `" type="audio/mpeg">`;
            
            //将audio节点追加到dom
            document.body.appendChild(audio);
            audio.load();
            
            //iOS Safari可能是出于防止骚扰用户的考虑，首次非用户触发的play不会生效
            audio.play();
            audio.pause();
            
            document.addEventListener("WeixinJSBridgeReady", function () {
                //微信H5环境，监听WeixinJSBridgeReady事件，再次进行play
                //亲测iOS 微信H5页面能够自动播放
                document.getElementById('audio').play();
            }, false);
        }
        initMusic();

        (function(){
            let tr = document.querySelector('.cardtransition');
            tr.addEventListener(clickEvent,function(){
                tr.classList.add('active');
            });
            tr.addEventListener('transitionend',function(){
                document.querySelector('.christmas').classList.add('active');
                tr.classList.add('endActive');
                that.ArrayScrollAnimate();
            });
        })();

        const splitlist = function(splitlist,bool){
            Array.prototype.forEach.call(document.querySelectorAll(splitlist), function (item) {
                let flag = false,
                    isRandom = bool,
                    delays = parseInt(item.getAttribute('delay')),
                    speeds = parseInt(item.getAttribute('speed')),
                    Arrays = item.innerHTML.replace(/<br>/g, "\n").replace(/<i>/g, "\\").replace(/<\/i>/g, "\t").replace(/&amp;/g, "&").split("");
                item.innerHTML = '';
                if(!delays){
                    delays = 300
                }
                if(!speeds){
                    speeds = 100
                }
                Array.prototype.forEach.call(Arrays,function(letter, i) {
                    let span = document.createElement("span"),
                        br = document.createElement("br"),
                        random = 1;
                    if(letter.indexOf("\n") >= 0){
                        item.appendChild(br);
                        return
                    }
                    if(letter.indexOf("\\") >= 0){
                        flag = true;
                        return
                    }
                    if(letter.indexOf("\t") >= 0){
                        flag = false;
                        return
                    }
                    if(flag){
                        span.className = 'letters';
                    }
                    if(isRandom){
                        random = Math.random();
                    }
                    delays += speeds;
                    span.style.animationDelay = delays * random  + 'ms';
                    span.innerHTML = letter;
                    item.appendChild(span);
                });
            });
        };
        splitlist('.splitlist',false);
        
        document.querySelector('.cardsetting .items').addEventListener('scroll',function(){
            let scrolly = document.querySelector('.cardsetting .items').scrollTop;
            that.ArrayScrollAnimate();
            that.itemAnimates();
            function draw(){
                document.querySelector('.bannerimg img').style.transform = 'translate3d(0,' + scrolly / 2.2 + 'px,0)';
            };
            draw();
            try {
                requestAnimationFrame(draw)
            } catch (_) {
                setImmediate(draw)
            };
        });

        document.querySelector('.card').addEventListener('scroll',function(){
            let scrolly = document.querySelector('.card').scrollTop;
            that.ArrayScrollAnimate();
            function draw(){
                document.querySelector('.cardtree img').style.transform = 'translate3d(0,' + scrolly / 2.2 + 'px,0)';
            };
            draw();
            try {
                requestAnimationFrame(draw)
            } catch (_) {
                setImmediate(draw)
            };
        });
    }
    htmlcanvas(){
        if(!document.querySelector('.bottomsup').classList.contains('flag')){
            return
        }
        document.querySelector('.splitlists').classList.remove('splitlist');
        document.querySelector('.splitlists').classList.remove('flags');
        document.querySelector('.splitlists').classList.remove('flag');
        document.querySelector('.splitlistsh6').classList.remove('flags');
        document.querySelector('.splitlistsh5').classList.remove('flags');
        document.querySelector('.splitlistsimg').classList.remove('flags');
        document.querySelector('.cardUserset').style.display = 'none';
        document.querySelector('.cardtree img').style.transform = 'translate3d(0,' + 0 + 'px,0)';  
        let wrapper = document.querySelector('.cardbox'),
            img = document.querySelector('.cardDownload'),
            Option = {
                width: wrapper.offsetWidth,
                height: wrapper.scrollHeight,
                scale: 3,
                scrollY: 0, 
                scrollX: 0,
            };
        html2canvas(wrapper, Option).then(function (canvas) {
            img.style.display = 'block';
            img.src = canvas.toDataURL('image/png');
            document.querySelector('.cardsetting').classList.remove('active');
        });
    }
    userSetting(){
        let setWrapper = document.querySelector('.cardsetting');
        setWrapper.classList.add('active');
        let scrolly = document.querySelector('.cardsetting .items').scrollTop;
        this.ArrayScrollAnimate();
    }
    itemAnimates(){
        let itemAnimates = document.querySelectorAll(".itemAnimates");
        if(!itemAnimates){return}
        for (let i = 0; i < itemAnimates.length; i++) {
            let itemAnimate = itemAnimates[i].querySelectorAll('.itemAnimate');
            let delay = 0;
            for (let j = 0; j < itemAnimate.length; j++) {
                if(itemAnimates[i].getAttribute('random') == '1'){
                    delay = Math.random() * itemAnimates[i].getAttribute('randomMax');
                    itemAnimate[j].style.transitionDelay = delay + "ms";
                }else{
                    delay += 100;
                    itemAnimate[j].style.animationDelay = delay + "ms";
                }
            }
        }
    }
    ArrayScrollAnimate(){
        Array.prototype.forEach.call(document.querySelectorAll('.flags'),function(slider){
            const top = slider.getBoundingClientRect().top;
            const viewHeight =window.innerHeight || document.documentElement.clientHeight || document.body.clientHeight;    
            if (top + 100 <= viewHeight ) {
                slider.classList.add('flag');
            }
        });
    }
    userSettingClose(){
        let setWrapper = document.querySelector('.cardsetting');
        setWrapper.classList.remove('active');
    }
    render() {
        let style = {
            fontSize : this.state.fontsize + 'rem',
            color : this.state.color,
            fontWeight : this.state.fontWeight,
            lineHeight : this.state.lineHeight,
            letterSpacing: this.state.letterSpacing  + 'px'
        }
        let substyle = {
            fontSize : this.state.subfontsize + 'rem',
            color : this.state.subcolor,
            fontWeight : this.state.subfontWeight,
            lineHeight : this.state.sublineHeight,
            letterSpacing: this.state.subletterSpacing  + 'px'
        }
        let astyle = {
            fontSize : this.state.afontsize + 'rem',
            color : this.state.acolor,
            fontWeight : this.state.afontWeight,
            lineHeight : this.state.alineHeight,
            letterSpacing: this.state.aletterSpacing  + 'px'
        }
        return (
            <div className="christmas">
                <div className="cardtransition  "></div>
                <div className="card">
                    <div className="cardbox" id="capture">
                        <div className="cardtree">
                            <img src={require("./img/9.png").default} alt=""/>
                        </div>
                        <div className="carddeer">
                            <img src={require("./img/10.png").default} alt=""/>
                        </div>
                        <div className="cardpaper">
                            <img className="lefthand" src={require("./img/11.png").default} alt=""/>
                            <img className="righthand" src={require("./img/12.png").default} alt=""/>
                            <h5 className="flags splitlistsh5" style={style} dangerouslySetInnerHTML={{ __html: this.state.fontText}}></h5>
                            <h6 className="flags splitlistsh6" style={substyle} dangerouslySetInnerHTML={{ __html: this.state.subfontText}}></h6>
                            <div className="text">
                                <p className="splitlist splitlists flags" speed="50" style={astyle} dangerouslySetInnerHTML={{ __html: this.state.afontText}}></p>
                            </div>
                            <button className="cardUserset flags" onClick={() => {this.userSetting()}}>
                                <i className="iconfont">&#xe6a6;..</i>
                            </button>
                            <img className="bottomsup flags splitlistsimg" src={require("./img/13.png").default} alt=""/>
                        </div>
                    </div>
                    <img src="" className="cardDownload" alt=""/>
                </div>
                <div className="cardReverse">
                    <div className="cardReverseBgbox">
                        <div className="cardReverseBg">
                        </div>
                        <div className="cardReverseBg">
                        </div>
                    </div>
                    <div className="cardReverseHeadbg">
                        <img src={require("./img/2.png").default} alt=""/>
                    </div>
                    <div className="cardReverseHead">
                        <img src={require("./img/3.png").default} alt=""/>
                        <img src={require("./img/4.png").default} alt=""/>
                        <img src={require("./img/5.png").default} alt=""/>
                        <img src={require("./img/7.png").default} alt=""/>
                        <img src={require("./img/6.png").default} alt=""/>
                        <img src={require("./img/5.png").default} alt=""/>
                        <img src={require("./img/7.png").default} alt=""/>
                        <img src={require("./img/6.png").default} alt=""/>
                    </div>
                    <div className="cardReversebody">
                        <img className="deer" src={require("./img/0.png").default} alt=""/>
                        <img className="merryText" src={require("./img/1.png").default} alt=""/>
                    </div>
                </div>
                <div className="cardsetting">
                    <div className="items">
                        <div className="cardsettingHead">
                            <div className="bannertext">
                                <i onClick={() => {this.userSettingClose()}} className="iconfont">&#xe600;</i>
                            </div>
                            <div className="bannerimg">
                                <img src={require("./img/14.png").default} alt=""/>
                            </div>
                        </div>
                        <TheTitle getdata={this.getDatas.bind(this)} fontText={this.state.fontText}  fontsize={style.fontSize} fontColor={style.color}
                        fontWeight={style.fontWeight} lineHeight={style.lineHeight} letterSpacing={this.state.letterSpacing}/>
                        <TheSubTitle getdata={this.subgetDatas.bind(this)} fontText={this.state.subfontText}  fontsize={substyle.fontSize} fontColor={substyle.color}
                        fontWeight={substyle.fontWeight} lineHeight={substyle.lineHeight} letterSpacing={this.state.subletterSpacing}/>
                        <TheAText getdata={this.agetDatas.bind(this)} fontText={this.state.afontText}  fontsize={astyle.fontSize} fontColor={astyle.color}
                        fontWeight={astyle.fontWeight} lineHeight={astyle.lineHeight} letterSpacing={this.state.aletterSpacing}/>
                        <div className="end">
                            <button className="thend" onClick={() => {this.htmlcanvas()}}>生成图片</button>
                            <p>*记得长按图片保存哟 ！</p>
                        </div>
                    </div>
                </div>
            </div>
        );
    }
}

export default christmas;

    