import React from "react";

class theAText extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            fontText:this.props.fontText,
            fontsize: this.props.fontSize,
            color: this.props.fontColor,
            fontWeight: this.props.fontWeight,
            lineHeight:this.props.lineHeight,
            letterSpacing:this.props.letterSpacing
        };
        this.setWeights = React.createRef();
    };
    componentDidMount() {
        const clickEvent = (function () {
            if ('ontouchstart' in document.documentElement === true) {
                return 'touchstart';
            } else {
                return 'mousedown';
            }
        })();
        let that = this;

        (function(){
            let  cardTitle = document.querySelector('.cardTitle3');
            cardTitle.addEventListener('input',function(){

            });
            cardTitle.addEventListener('blur',function(){
                that.setState({ fontText: cardTitle.innerHTML},() => {
                    that.handleClick();
                 });
            })
        })();
        (function () {
            let items = document.querySelectorAll('.setcolorbox3 .dot circle');
            for (let i = 0; i < items.length; i++) {
                if(getComputedStyle(items[i], null).stroke === that.state.color){
                    items[i].classList.add('active');
                    document.documentElement.style.setProperty('--color',that.state.color);
                }
                items[i].addEventListener(clickEvent, function () {
                    for (let i = 0; i < items.length; i++) {
                        items[i].classList.remove('active');
                    }
                    items[i].classList.add('active');
                })
            }
        })();
        (function () {
            let items = that.setWeights.current.querySelectorAll('.weight');
            for (let i = 0; i < items.length; i++) {
                if(items[i].getAttribute('data-weight') == that.state.fontWeight){
                    items[i].classList.add('active');
                }
                items[i].addEventListener('click', function () {
                    for (let i = 0; i < items.length; i++) {
                        items[i].classList.remove('active');
                    }
                    items[i].classList.add('active');
                })
            }
        })();
        function Pdd() {
            let bool = false,
                box = document.querySelector("#rangeBox2"),
                line = document.querySelector("#rangeline2 span"),
                dot = document.querySelector("#rangedot2"),
                lineWidth = line.offsetWidth,
                ratio = (lineWidth * .10 / lineWidth * 3).toFixed(2);
            dot.style.left = 10 + '%';
            that.setState({ fontsize: ratio },() =>{
                that.handleClick();
            });
            let start = function () {
                bool = true;
            }
            let move = function (e) {
                if (bool) {
                    let w = (document.querySelector('html').offsetWidth - document.querySelector('body').offsetWidth) / 2;
                    let x;
                    if (!e.touches) {
                        x = e.pageX - w - box.offsetLeft;
                    } else {
                        x = e.touches[0].pageX;
                    }
                    if (x <= 0) {
                        x = 0;
                    }
                    if (x >= lineWidth) {
                        x = lineWidth;
                    }
                    ratio = (x / lineWidth * 3).toFixed(2);
                    that.setState({ fontsize: ratio });
                    dot.style.left = x + 'px';
                    that.handleClick();
                }
            }
            let end = function () {
                bool = false;
            }
            dot.addEventListener("mousedown", start);
            dot.addEventListener("touchstart", start);
            box.addEventListener("mousemove", move);
            box.addEventListener("touchmove", move);
            box.addEventListener("mouseup", end);
            box.addEventListener("touchend", end);
        }
        Pdd();
    }
    setcolor(e) {
        this.setState({ color: getComputedStyle(e.target, null).stroke },()=>{
           this.handleClick();
        });
    }
    setfontWeight(e) {
        this.setState({ fontWeight: e.currentTarget.getAttribute('data-weight')},()=>{
           this.handleClick();
        });
    }
    setlineHeightprev(e){
        if(this.state.lineHeight >= 3){
            return
        }else{
            this.state.lineHeight += 0.1;
        }
        this.setState({ lineHeight: this.state.lineHeight},()=>{
           this.handleClick();
        });
    }
    setlineHeightnext(e){
        if(this.state.lineHeight <= .8){
            return
        }else{
            this.state.lineHeight -= 0.1;
        }
        this.setState({ lineHeight: this.state.lineHeight},()=>{
           this.handleClick();
        });
    }
    setletterSpacingprev(e){
        if(this.state.letterSpacing >= 15){
            return
        }else{
            this.state.letterSpacing += 1;
        }
        this.setState({ letterSpacing: this.state.letterSpacing},()=>{
           this.handleClick();
        });
    }
    setletterSpacingnext(e){
        if(this.state.letterSpacing <= -10){
            return
        }else{
            this.state.letterSpacing -= 1;
        }
        this.setState({ letterSpacing: this.state.letterSpacing},()=>{
           this.handleClick();
        });
    }
    handleClick(){
        this.props.getdata(
            this.state.fontText,
            this.state.fontsize,
            this.state.color,
            this.state.fontWeight,
            this.state.lineHeight,
            this.state.letterSpacing
        );
    }
    render() {
        let style = {
            fontSize: this.state.fontsize + 'rem',
            color: this.state.color,
            fontWeight : this.state.fontWeight,
            lineHeight : this.state.lineHeight,
            letterSpacing : this.state.letterSpacing + 'px'
        }
        return (
            <div className="item">
                <div className="head">
                    <div>
                        <img src={require("../img/24.svg").default} alt=""/>
                    </div>
                    <h5 className="splitlist flags">正文</h5>
                    <div>
                        <img src={require("../img/24.svg").default} alt=""/>
                    </div>
                </div>
                <div className="cardTitleBox" style={{background : `linear-gradient(45deg, `+ this.state.color + `25%, white 25%, white 50%,`+ this.state.color + ` 50%,` +  this.state.color + ` 75%, white 75%, white)` , background : `-webkit-linear-gradient(45deg, `+ this.state.color + `25%, white 25%, white 50%,`+ this.state.color + ` 50%,` +  this.state.color + ` 75%, white 75%, white)`}}>
                    <div className="cardTitle cardTitle3" contentEditable="true" suppressContentEditableWarning="true" style={style} dangerouslySetInnerHTML={{ __html: this.state.fontText}}></div>
                </div>
                <div className="setting">
                    <div className="setfontsize">
                        <div className="setHead">
                            <h6 className="splitlist flags">大小</h6>
                            <div><img src={require("../img/17.svg").default} alt=""/></div>
                        </div>
                        <div className="rangeBox" id="rangeBox2">
                            <div className="rangeline" id="rangeline2">
                                <span></span>
                            </div>
                            <div className="rangedot" id="rangedot2" style={{backgroundColor : this.state.color}}></div>
                        </div>
                    </div>
                    <div className="setcolor">
                        <div className="setHead">
                            <h6 className="splitlist flags">颜色</h6>
                            <div><img src={require("../img/19.svg").default}/></div>
                        </div>
                        <div className="setcolorbox setcolorbox3 itemAnimates" random="1" randommax="600">
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle id="circle1" cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                            <svg className="dot itemAnimate flags" onClick={(e) => { this.setcolor(e) }}>
                                <circle cx="50%" cy="50%" r=".3rem" />
                            </svg>
                        </div>
                    </div>
                </div>
                <div className="settingbox">
                        <div className="settingboxItem">
                            <div className="setHead">
                                <h6 className="splitlist flags">粗细</h6>
                                <div><img src={require("../img/20.svg").default} alt=""/></div>
                            </div>
                            <div className="setWeight itemAnimates flags" ref={this.setWeights}>
                                <div className="weight itemAnimate" data-weight="100" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Thin</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="200" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Extra Light</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="300" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Light</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="400" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Regular</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="500" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Medium</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="600" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Semi Bold</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                                <div className="weight itemAnimate" data-weight="700" onClick={(e) => { this.setfontWeight(e) }}>
                                    <p>Bold</p>
                                    <div><img src={require("../img/18.svg").default} alt=""/></div>
                                </div>
                            </div>
                        </div>
                        <div className="settingboxItem">
                            <div className="setHead">
                                <h6 className="splitlist flags">行距</h6>
                                <div><img src={require("../img/21.svg").default} alt=""/></div>
                            </div>
                            <div className="setlineHeight">
                                <div className="box">
                                    <i className="iconfont" onClick={(e) => { this.setlineHeightprev(e) }} >增加</i>
                                    <div>{this.state.lineHeight.toFixed(1)}</div>
                                    <i className="iconfont" onClick={(e) => { this.setlineHeightnext(e) }} >减少</i>
                                </div>
                            </div>
                        </div>
                        <div className="settingboxItem">
                            <div className="setHead">
                                <h6 className="splitlist flags">间距</h6>
                                <div><img src={require("../img/22.svg").default} alt=""/></div>
                            </div>
                            <div className="setlineHeight">
                                <div className="box">
                                    <i className="iconfont" onClick={(e) => { this.setletterSpacingprev(e) }} >增加</i>
                                    <div>{this.state.letterSpacing}px</div>
                                    <i className="iconfont" onClick={(e) => { this.setletterSpacingnext(e) }} >减少</i>
                                </div>
                            </div>
                        </div>
                    </div>
            </div>
        );
    }
}

export default theAText;
